protected void endPost()
{
    next endPost();


    CustPackingSlipJour packingSlipJour = this.parmJournalTable() as CustPackingSlipJour;


    if (packingSlipJour && packingSlipJour.RecId != 0)
    {

        //info(strFmt("Business event sent to queue for Sales Packing Slip: %1", packingSlipJour.PackingSlipId));


        SalesPackingSlipBusinessEvent::newFromCustPackingSlipJour(packingSlipJour).send();
    }
}
